+					"contents": []map[string]interface{}{
+						{
+							"text": `[{"name":"BlueLake","program":"codex","model":"gpt-5"}]`,
+						},
+					},
+				},
+			})
+		default:
+			t.Fatalf("unexpected method: %s", req.Method)
+		}
+	}))
+	defer server.Close()
+
+	t.Setenv("AGENT_MAIL_URL", server.URL+"/")
