+	corr := buildCorrelationGraph()
+	if corr == nil {
+		t.Fatal("expected correlation graph")
+	}
+	if got := corr.MailSummary[threadRead].Unread; got != 0 {
+		t.Fatalf("MailSummary[%s].Unread = %d, want 0", threadRead, got)
